using CertDesk.Models; using CertDesk.Services;
namespace CertDesk.Forms;
public sealed class TokensView:UserControl
{ readonly User user; readonly TokenService service; readonly DataGridView grid=Ui.Grid(); readonly TextBox search=Ui.TextBox(); readonly ComboBox status=Ui.Combo();
 public TokensView(User user){this.user=user; service=new(user); var top=new FlowLayoutPanel{Dock=DockStyle.Top,Height=88}; status.Items.AddRange(["Все","storage","issued","damaged","written_off"]); status.SelectedIndex=0; var add=Ui.Button("Добавить"); var edit=Ui.Button("Изменить"); var issue=Ui.Button("Выдать"); var ret=Ui.Button("Вернуть"); var dmg=Ui.Button("Поврежден"); var off=Ui.Button("Списать"); var refresh=Ui.Button("Обновить"); top.Controls.AddRange([Ui.Label("Поиск"),search,Ui.Label("Статус"),status,add,edit,issue,ret,dmg,off,refresh]); Controls.Add(grid); Controls.Add(top); search.TextChanged+=(_,_)=>LoadData(); status.SelectedIndexChanged+=(_,_)=>LoadData(); refresh.Click+=(_,_)=>LoadData(); add.Click+=(_,_)=>Open(0); edit.Click+=(_,_)=>Open(Id()); issue.Click+=(_,_)=>Issue(); ret.Click+=(_,_)=>Op(()=>service.Return(Id(),"Возврат пользователем")); dmg.Click+=(_,_)=>Op(()=>service.Damage(Id(),"Отмечен как поврежден")); off.Click+=(_,_)=>Op(()=>service.WriteOff(Id(),"Списание токена")); if(!AuthService.CanEdit(user)){add.Visible=edit.Visible=issue.Visible=ret.Visible=dmg.Visible=off.Visible=false;} LoadData();}
 int Id()=>grid.CurrentRow==null?0:Convert.ToInt32(grid.CurrentRow.Cells["id"].Value); bool EnsureEdit(){if(!AuthService.CanEdit(user)){MessageBox.Show("Недостаточно прав для выполнения операции");return false;} return Id()>0;} void Open(int id){if(!AuthService.CanEdit(user)){MessageBox.Show("Недостаточно прав для выполнения операции");return;} using var f=new TokenEditForm(service.Get(id)??new Token{ReceivedAt=DateTime.Today},service); if(f.ShowDialog()==DialogResult.OK)LoadData();} void Issue(){if(!EnsureEdit())return; using var f=new TokenIssueForm(Id(),service); if(f.ShowDialog()==DialogResult.OK)LoadData();} void Op(Action a){if(!EnsureEdit())return; try{a();LoadData();}catch(Exception ex){Ui.Error(ex);}} void LoadData(){grid.DataSource=service.Search(search.Text,status.Text); if(grid.Columns.Contains("id"))grid.Columns["id"].Visible=false;}
}
